  let dir  = normalize(seg.b - seg.a);
  let perp = vec2f(-dir.y, dir.x);
  let u    = quadU[vi];
  let v    = quadV[vi];
  let p    = mix(seg.a, seg.b, u) + perp * v * seg.w * 0.5;
  var o:VO;
